package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    public int x;
  }

  static class NonRecord {
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() throws Exception {
    // Use reflection to get the private static final RECORD_HELPER field
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class)) {
      Object mockRecordHelper = mock(recordHelperField.getType());
      // Replace the RECORD_HELPER field value via reflection
      recordHelperField.set(null, mockRecordHelper);

      when(recordHelperField.getType().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class))
          .thenReturn(true);

      // Since we cannot mock the method call on the mock via reflection easily, use doReturn:
      // Instead, we stub the method on the mockRecordHelper:
      when(((com.google.gson.internal.reflect.RecordHelper)mockRecordHelper).isRecord(TestRecord.class)).thenReturn(true);

      boolean result = ReflectionHelper.isRecord(TestRecord.class);

      assertTrue(result);
      verify((com.google.gson.internal.reflect.RecordHelper)mockRecordHelper).isRecord(TestRecord.class);
    }
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() throws Exception {
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class)) {
      Object mockRecordHelper = mock(recordHelperField.getType());
      recordHelperField.set(null, mockRecordHelper);

      when(((com.google.gson.internal.reflect.RecordHelper)mockRecordHelper).isRecord(NonRecord.class)).thenReturn(false);

      boolean result = ReflectionHelper.isRecord(NonRecord.class);

      assertFalse(result);
      verify((com.google.gson.internal.reflect.RecordHelper)mockRecordHelper).isRecord(NonRecord.class);
    }
  }
}
